targets.rawSql:
SELECT COUNT(*) AS "총 Trace 수"
FROM traces
WHERE $__timeFilter(timestamp);

SELECT SUM(COALESCE(total_tokens, 0)) AS "총 토큰 사용량"
FROM observations
WHERE $__timeFilter(start_time);

SELECT COUNT(DISTINCT session_id) AS "총 세션 수"
FROM traces
WHERE $__timeFilter(timestamp) AND session_id IS NOT NULL;
